+#[inline]
+fn fallback_wrap_plan(
+    tokens: &[Cell],
+    width: usize,
+    estimated_states: usize,
+    evaluated_states: usize,
+) -> MonospaceWrapPlan {
+    MonospaceWrapPlan {
+        mode: MonospaceWrapMode::Fallback,
+        break_offsets: greedy_break_offsets_from_tokens(tokens, width),
+        estimated_states,
+        evaluated_states,
+    }
+}
